MST.TB_IP_BLOCK_MST A
SET

	A.NIP_BLOCK_MST_SEQ = #{nipBlockMstSeq, jdbcType=BIGINT}


	,	A.SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}


	,	A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}


	,	A.SIP_BLOCK = #{sipBlock, jdbcType=VARCHAR}


	,	A.SIP_CREATE_SEQ_CD = #{sipCreateSeqCd, jdbcType=VARCHAR}


	,	A.NBITMASK = #{nbitmask, jdbcType=INTEGER}


	,	A.SNETMASK = #{snetmask, jdbcType=VARCHAR}


	,	A.SFIRST_ADDR = #{sfirstAddr, jdbcType=VARCHAR}


	,	A.SLAST_ADDR = #{slastAddr, jdbcType=VARCHAR}


	,	A.NFIRST_ADDR = #{nfirstAddr, jdbcType=NUMERIC}


	,	A.NLAST_ADDR = #{nlastAddr, jdbcType=NUMERIC}


	,	A.SFIRST_IP_PREFERRED = #{sfirstIpPreferred, jdbcType=VARCHAR}


	,	A.SLAST_IP_PREFERRED = #{slastIpPreferred, jdbcType=VARCHAR}


	,	A.SFIRST_ADDR_BINARY = #{sfirstAddrBinary, jdbcType=VARCHAR}


	,	A.SLAST_ADDR_BINARY = #{slastAddrBinary, jdbcType=VARCHAR}


	,	A.NCNT = #{ncnt, jdbcType=NUMERIC}


	,	A.NCLASS_CNT = #{nclassCnt, jdbcType=NUMERIC}


	,	A.NUSE_IP_CNT = #{nuseIpCnt, jdbcType=NUMERIC}


	,	A.NFREE_IP_CNT = #{nfreeIpCnt, jdbcType=NUMERIC}



			,	A.SCOMMENT = #{scomment, jdbcType=VARCHAR}


			,	A.SCOMMENT = NULL



	,	A.DCREATE_DT = #{dcreateDt, jdbcType=TIMESTAMP}


	,	A.SCREATE_ID = #{screateId, jdbcType=VARCHAR}





	,	A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

	,	A.DMODIFY_DT = sysdate
WHERE A.NIP_BLOCK_MST_SEQ = #{nipBlockMstSeq, jdbcType=BIGINT}

