SELECT
, A.RNUM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM FROM ( SELECT
, ROWNUM RNUM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM FROM ( SELECT
, H.SLVL_NM AS SSVC_GROUP_NM , I.SLVL_NM as SSVC_OBJ_NM FROM MST.TB_IP_BLOCK_MST A
, MST.TB_LVL_MST G , MST.TB_LVL_CD H , MST.TB_LVL_CD I
AND A.NLVL_MST_SEQ = G.NLVL_MST_SEQ(+) AND G.SSVC_GROUP_CD = H.SLVL_CD(+) AND G.SSVC_OBJ_CD = I.SLVL_CD(+)
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

