	count(1) totalCount
FROM MST.TB_IP_BLOCK_MST A




	AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}


	AND A.NLVL_MST_SEQ IN 

		#{item.nlvlSeq}

SELECT COUNT(NIP_BLOCK_MST_SEQ) AS CNT
FROM MST.TB_IP_BLOCK_MST
WHERE 1=1
AND (
		(NFIRST_ADDR <= #{nfirstAddr, jdbcType=NUMERIC} AND NLAST_ADDR >= #{nlastAddr, jdbcType=NUMERIC})
		OR (NFIRST_ADDR >= #{nfirstAddr, jdbcType=NUMERIC} AND NFIRST_ADDR <= #{nlastAddr, jdbcType=NUMERIC})
		OR (NLAST_ADDR >= #{nfirstAddr, jdbcType=NUMERIC} AND NLAST_ADDR <= #{nlastAddr, jdbcType=NUMERIC})
		OR (NFIRST_ADDR >= #{nfirstAddr, jdbcType=NUMERIC} AND NLAST_ADDR <= #{nlastAddr, jdbcType=NUMERIC})
	)
AND SIP_CREATE_TYPE_CD = 'CT0005' 
AND SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}	 
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
